      return cache.addAll([
        '/',
        '/index.html',
        '/styles/main.css',
        '/js/app.js'
      ]);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});
```

### 2. Manifest文件

manifest.json定义了应用的元数据和外观。

```json
{
  "name": "Pixel Astro",
  "short_name": "Astro",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#1a1a2e",
  "theme_color": "#16213e",
  "icons": [
    {
